用n%10逐位取数字，n/=10去掉最低位，用长度为10的数组计数。

```cpp
#include <bits/stdc++.h>
using namespace std;

int main() {
    long long n;
    cin >> n;
    int cnt[10] = {0};
    while (n > 0) {
        cnt[n % 10]++;
        n /= 10;
    }
    for (int i = 0; i < 10; i++) {
        if (i > 0) cout << " ";
        cout << cnt[i];
    }
    cout << endl;
    return 0;
}
```

外层循环按组遍历（步长g），内层累加该组g人成绩（最后一组不足g人注意边界）。用fixed和setprecision(1)保留一位小数。

```cpp
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, g;
    cin >> n >> g;
    int a[105];
    for (int i = 0; i < n; i++) cin >> a[i];
    for (int i = 0; i < n; i += g) {
        double sum = 0;
        int cnt = 0;
        for (int j = i; j < n && j < i + g; j++) {
            sum += a[j];
            cnt++;
        }
        cout << fixed << setprecision(1) << sum / cnt << endl;
    }
    return 0;
}
```

用三个变量统计。性别用if判断，转学生用substr(name.size()-2)检查'_T'后缀。

```cpp
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    int male = 0, female = 0, transfer = 0;
    for (int i = 0; i < n; i++) {
        string name;
        char gender;
        cin >> name >> gender;
        if (gender == 'M') male++;
        else female++;
        if (name.size() >= 2 && name.substr(name.size() - 2) == "_T")
            transfer++;
    }
    cout << male << endl << female << endl << transfer << endl;
    return 0;
}
```

用数组cnt[101]计票（候选人编号做下标）。遍历数组找最大值，因为从小到大遍历，平票时自动取最小编号。

```cpp
#include <bits/stdc++.h>
using namespace std;

int main() {
    int m;
    cin >> m;
    int cnt[101] = {0};
    for (int i = 0; i < m; i++) {
        int x;
        cin >> x;
        cnt[x]++;
    }
    int maxVote = 0, winner = 0;
    for (int i = 1; i <= 100; i++) {
        if (cnt[i] > maxVote) {
            maxVote = cnt[i];
            winner = i;
        }
    }
    cout << winner << endl;
    return 0;
}
```

二分查找。用指针标记查找区间，每次取中间位置与目标比较，缩小范围直至找到或区间为空。

```cpp
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, target;
    cin >> n >> target;
    int a[1005];
    for (int i = 0; i < n; i++) cin >> a[i];
    int *low = a;
    int *high = a + n - 1;
    while (low <= high) {
        int *mid = low + (high - low) / 2;
        if (*mid == target) {
            cout << (mid - a) << endl;
            return 0;
        } else if (*mid < target) {
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    cout << -1 << endl;
    return 0;
}
```
